diff --git a/servers/api/src/app/services/users.service.ts b/servers/api/src/app/services/users.service.ts
index 36e74391..89ae61aa 100644
--- a/servers/api/src/app/services/users.service.ts
+++ b/servers/api/src/app/services/users.service.ts
@@ -342,15 +342,18 @@ export class UsersService extends BaseService {
       if (!user) {
         return {
           status: 'not_created', // Change to 'unknown' if you want to hide existence of the account
+          userId: null,
         };
       } else if (user.emailVerified) {
         return {
           status: 'verified', // Change to 'unknown' if you want to hide existence of the account
+          userId: user.id,
         };
       }

       return {
         status: 'not_verified',
+        userId: user.id,
       };
     });
   }

