    // (this also serves as a test for cleanUserIfDeactivated)
    const firstSignupResult = await request(app.getHttpServer())
      .post(`/api/auth/signup`)
      .set({
        'Accept-Language': data.lang,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .send({
        email: data.email,
        name: data.name,
        birthday: data.birthday,
        inviteMode: data.inviteMode,
      })
      .expect(201);

    // await UserTestUtil.expectDeletionOfUserRelatedRecords(
    //   dataSource,
    //   pendingDeletionUserRecords,
    // );

    const firstUserId = firstSignupResult.body.userId as string;
    const firstUserRelatedRecords =
      await UserTestUtil.expectAndExtractUserRelatedRecords(
        dataSource,
        firstUserId,
      );

    // resend email by signup again
    // (test that this does not delete the user)
    const signupResult = await request(app.getHttpServer())
      .post(`/api/auth/signup`)
      .set({
        'Accept-Language': data.lang,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .send({
        email: data.email,
        inviteMode: data.inviteMode,
      })
      .expect(201);

    await UserTestUtil.expectPreservationOfUserRelatedRecords(
      dataSource,
      firstUserRelatedRecords,
    );
    const userId = signupResult.body.userId as string;
    expect(firstUserId).toBe(userId);

    return userId;
  };

