    await request(app.getHttpServer())
      .put(`/api/auth/password-reset`)
      .set({
        'Accept-Language': lang,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .send({
        userId,
        password,
        token: userInDatabase?.emailVerificationToken,
      })
      .expect(200);

