      User,
      {
        where: {
          id: userId,
        },
      },
    );
    expect(userInDatabaseAfterPasswordReset?.emailVerified).toBe(true);

    const latestEmail = await TestUtil.getLatestEmailFromInbucket(httpService, {
      email,
      dateAfter: startingDate,
