    // Cannot signup after verification
    const signupResultAfterVerification = await request(app.getHttpServer())
      .post(`/api/auth/signup`)
      .set({
        'Accept-Language': lang,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .send({
        email,
        name,
        birthday,
        inviteMode: 'link',
      })
      .expect(400);

    return {
      email: latestEmail!,
      user: userInDatabase!,
    };
  };

  it(`Signup with Link (EN)`, async () => {
    const { email, user } = await signupWithLink('en');

    expect(email).toMatchObject({
      from: '<noreply@knowhere.co.jp>',
      subject: '[LOCAL] [SmartScout] User Registration',
    });
    expect(_.trim(email.body.html, '\n')).toMatch(
      invitation1HtmlEn(user.id, `${user.emailVerificationToken!}`),
    );
  });

  it(`Signup with Link (JA)`, async () => {
    const { email, user } = await signupWithLink('ja');

    expect(email).toMatchObject({
      from: '<noreply@knowhere.co.jp>',
      subject: '[LOCAL] [SmartScout] ユーザー登録',
    });
    expect(_.trim(email.body.html, '\n')).toMatch(
      invitation1HtmlJa(user.id, `${user.emailVerificationToken!}`),
    );
  });

  const signupWithCode = async (lang: 'en' | 'ja') => {
    // The sign up flow with verification code
    // 1. Create a user by /api/auth/signup with email (and optional user name).
    // 2. API server sends to the user a verification code via email.
    // 3. Get a temporary token by /api/auth/code-verification with the verification code.
    // 4. Initialize password by /api/auth/reset-password/initial with the temporary token.

    const startingDate = new Date();
    const password = 'test123';
    const randomStr = StringUtil.getRandomHex().hex;
    const email = `testcase_invited_${randomStr}@example.com`;
    const name = 'test';
    const birthday = '2000-01-01';

    const userId = await signup({
      email,
      name,
      birthday,
      inviteMode: 'code',
      lang,
    });
    const userProfile = await dataSource.manager.findOne(Profile, {
      where: {
        id: userId,
      },
    });
    expect(userProfile?.username).toBe(name);
    expect(userProfile?.birthday).toBe(birthday);

    const userInDatabase = await dataSource.manager.findOne(User, {
      where: {
        id: userId,
      },
    });
    expect(userInDatabase?.verificationCode).toBeTruthy();

    // With wrong code
    await request(app.getHttpServer())
      .get(`/api/auth/code-verification`)
      .set({
        'Accept-Language': lang,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .query({
        email,
        code: 'wrong code',
      })
      .expect(400);

    // With correct code
    const resultOfCorrectCodeVerification = await request(app.getHttpServer())
      .get(`/api/auth/code-verification`)
      .set({
        'Accept-Language': lang,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .query({
        email,
        code: userInDatabase!.verificationCode!,
      })
      .expect(200);

    const userInDatabaseAfterCodeVerification =
      await dataSource.manager.findOne(User, {
        where: {
          id: userId,
        },
      });
    expect(userInDatabaseAfterCodeVerification?.temporallyToken).toBeTruthy();

    expect(resultOfCorrectCodeVerification.body.token).toMatch(
      userInDatabaseAfterCodeVerification!.temporallyToken!,
    );
    expect(userInDatabaseAfterCodeVerification?.emailVerified).toBe(true);

    await request(app.getHttpServer())
      .put(`/api/auth/password-reset/initial`)
      .set({
        'Accept-Language': lang,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
