  });

  describe('GET /auth/users/verification-status', () => {
    it('should return not_created for non-existent user', async () => {
      const nonExistentEmail = `non_existent_${StringUtil.getRandomHex().hex}@example.com`;

      const response = await request(app.getHttpServer())
        .get('/api/auth/users/verification-status')
        .query({ email: nonExistentEmail })
        .set({
          'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
        })
        .expect(200);

      expect(response.body).toEqual({
        status: 'not_created',
      });
    });

    it('should return verified for email-verified user', async () => {
      const randomStr = StringUtil.getRandomHex().hex;
      const email = `verified_user_${randomStr}@example.com`;
      const userId = uuidv4();

      // Create a verified user
      await dataSource.manager.save(User, {
        id: userId,
        email: email,
        hashedPassword: 'dummy_hash',
        emailVerified: true,
        createdAt: new Date(),
        updatedAt: new Date(),
      });

      const response = await request(app.getHttpServer())
        .get('/api/auth/users/verification-status')
        .query({ email })
        .set({
          'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
        })
        .expect(200);

      expect(response.body).toEqual({
        status: 'verified',
      });

      // Cleanup
      await dataSource.manager.delete(User, { id: userId });
    });

    it('should return not_verified for user with password but not email-verified', async () => {
      const randomStr = StringUtil.getRandomHex().hex;
      const email = `unverified_with_password_${randomStr}@example.com`;
      const userId = uuidv4();

      // Create a user with hashedPassword but emailVerified = false
      // This simulates the edge case where user has password but hasn't verified email
      await dataSource.manager.save(User, {
        id: userId,
        email: email,
        hashedPassword: 'dummy_hash',
        emailVerified: false,
        createdAt: new Date(),
        updatedAt: new Date(),
      });

      const response = await request(app.getHttpServer())
        .get('/api/auth/users/verification-status')
        .query({ email })
        .set({
          'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
        })
        .expect(200);

      expect(response.body).toEqual({
        status: 'not_verified',
      });

      // Cleanup
      await dataSource.manager.delete(User, { id: userId });
    });
  });

  afterAll(async () => {
    await dataSource.destroy();
    await app.close();
  });
});

